// Worked focus: cmem-integer-ranges-ranks — Select integer types from range, signedness, rank, width, and representation requirements rather than familiar spelling.
/* Evidence: cmem-worked-cmem-values-integers-overflow-3 */
/* Browser practice: PicoC 3.2.2 C89/C90 plus selected C99. */
/* Changed case 6218; native C23 claims require explicit transfer gates. */
#include <stdio.h>
#include <stdlib.h>
#include <string.h>


static int worked_cmem_values_integers_overflow_3(size_t count, size_t width, size_t limit, size_t *bytes) {
  if (bytes == NULL || width == 0) return 0;
  if (count > limit / width) return 0;
  *bytes = count * width;
  return 1;
}

int main(void) {
  size_t bytes = 99;
  int rejected = worked_cmem_values_integers_overflow_3((size_t)22, (size_t)8, (size_t)64, &bytes);
  int accepted = worked_cmem_values_integers_overflow_3((size_t)2, (size_t)4, (size_t)64, &bytes);
  int invariant = !rejected && accepted && bytes == (size_t)8;
  printf("size bytes=%lu invariant=%d\n", (unsigned long)bytes, invariant);
  return invariant ? 0 : 1;
}

